.house-wings {
  position: absolute;
  bottom: 0;
  height: 125px;
}

.house-wings:before {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: white;
  border: 5px solid #224889;
  box-shadow: inset 0 15px #E1EAFF;
}

.house-wings:after {
  position: absolute;
  bottom: 0;
  left: 0;
  height: 5px;
  width: 100%;
  background-color: #224889;
  transform: scaleX(1.2);
}

.house-wings>.house-roof {
  height: 65px;
  width: calc(100% + 40px);
  left: -20px;
  border-bottom: 5px solid #224889;
  position: absolute;
  bottom: 100%;
}

.house-wings>.house-roof:before,
.house-wings>.house-roof:after {
  position: absolute;
  height: 100%;
  width: 50%;
  background-color: #A6CFFF;
  border: 5px solid #224889;
  border-bottom: none;
}

.house-wings>.house-roof:before {
  left: 0;
  transform-origin: bottom left;
  transform: skewX(-30deg);
  border-right: none;
}

.house-wings>.house-roof:after {
  right: 0;
  transform-origin: bottom right;
  transform: skewX(30deg);
  border-left: none;
}

.house-wings .house-ledge {
  position: absolute;
  bottom: -15px;
  width: 100%;
  height: 15px;
  border: 5px solid #224889;
  background-color: #79AAFF;
}

.house-facade {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  box-shadow: 15px 0 rgba(123, 163, 255, 0.2);
}

.house-facade:before,
.house-facade:after {
  position: absolute;
  height: 100%;
  width: 50%;
  background-color: #fff;
  top: 0;
  border-top: 5px solid #224889;
  box-shadow: inset 0 calc(var(--front-width) / 6) #E1EAFF;
}

.house-facade:before {
  left: 0;
  transform-origin: top left;
  transform: skewY(-40deg);
  border-left: 5px solid #224889;
}

.house-facade:after {
  right: 0;
  transform-origin: top right;
  transform: skewY(40deg);
  border-right: 5px solid #224889;
}

