.house-window {
  height: 60px;
  width: 30px;
  border: 5px solid #224889;
  border-top-left-radius: 30px;
  border-top-right-radius: 30px;
  background-image: linear-gradient(to right, #65EBFF, #65EBFF 49.9%, #71FBFF 50%, #71FBFF);
}

.house-window:before {
  height: 100%;
  width: 5px;
  left: calc(50% - 2.5px);
  top: 0;
  background-color: #224889;
}

.house-window:after {
  height: 15px;
  width: calc(100% + 20px);
  left: -10px;
  bottom: 5px;
  border-radius: 15px;
  background-color: #79AAFF;
  border: 5px solid #224889;
  box-shadow: 0 5px #E1EAFF;
}

.house-doorway {
  width: 65px;
  height: 90px;
  position: absolute;
  bottom: 0;
  left: calc(50% - 65px / 2);
}

.house-stairs {
  width: 100%;
  position: absolute;
  bottom: 0;
  left: 0;
  height: 15px;
  border: 5px solid #224889;
  z-index: 0;
  box-shadow: 5px -5px #E1EAFF;
}

.house-stairs,
.house-stairs:before,
.house-stairs:after {
  background-color: white;
}

.house-stairs:before,
.house-stairs:after {
  box-shadow: 5px -5px #E1EAFF;
  position: absolute;
  height: 15px;
  width: 100%;
  border: 5px solid #224889;
}

.house-stairs:before {
  bottom: 100%;
  transform: scaleX(0.9);
  z-index: 0;
}

.house-stairs:after {
  bottom: calc(200% + 5px);
  transform: scaleX(0.75);
  z-index: 0;
}

.house-door {
  position: absolute;
  background-color: #224889;
  width: 50%;
  height: 55px;
  left: 25%;
  bottom: 35px;
  border-top-left-radius: 2px;
  border-top-right-radius: 2px;
}
